#include <bits/stdc++.h>
using namespace std;

int mfac[1000005];
vector<int> p;

int main() {
    int n, b;
    cin >> n >> b;
    for (int i = 2; i <= n; i++) {
        if (!mfac[i]) {
            p.push_back(i);
            mfac[i] = i;    
            for (int j = i; j <= n; j += i) {
                mfac[j] = i;
            }
        }
    }
    int sum = 0;
    for (int i = 1; i <= n; i++)
        if (mfac[i] <= b) sum++;
    cout << sum;
    return 0;
}
